import { Component, signal, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { PurchaseOrder, PurchaseOrderLine, POStatus } from '../../core/models';

@Component({
  selector: 'app-po-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './po-detail.component.html',
})
export class PoDetailComponent {
  private route = inject(ActivatedRoute);

  orders = signal<PurchaseOrder[]>([
    {
      id: 'po1',
      reference: 'PO-1001',
      supplierId: 's1',
      supplierName: 'Acme Industrial Supply',
      status: 'ordered',
      createdAt: '2026-07-08',
      total: 560,
      lines: [
        { id: 'pol1', productId: 'p3', productName: 'PVC Pipe 50mm', sku: 'PIP-050', qty: 100, unitCost: 3.20 },
        { id: 'pol2', productId: 'p5', productName: 'Copper Wire 14AWG', sku: 'WIR-014', qty: 20, unitCost: 12.00 },
      ],
    },
    {
      id: 'po2',
      reference: 'PO-1002',
      supplierId: 's2',
      supplierName: 'Globex Materials',
      status: 'draft',
      createdAt: '2026-07-10',
      total: 375,
      lines: [
        { id: 'pol3', productId: 'p1', productName: 'Steel Bolt M8', sku: 'STL-001', qty: 500, unitCost: 0.45 },
        { id: 'pol4', productId: 'p2', productName: 'Steel Nut M8', sku: 'STL-002', qty: 500, unitCost: 0.30 },
      ],
    },
    {
      id: 'po3',
      reference: 'PO-1000',
      supplierId: 's1',
      supplierName: 'Acme Industrial Supply',
      status: 'received',
      createdAt: '2026-07-01',
      total: 725,
      lines: [
        { id: 'pol5', productId: 'p7', productName: 'Control Panel', sku: 'PNL-100', qty: 5, unitCost: 145.00 },
      ],
    },
  ]);

  id = inject(ActivatedRoute).snapshot.paramMap.get('id');

  order = computed(() => this.orders().find((o) => o.id === this.id) ?? this.orders()[0]);

  received = signal<boolean>(false);
  receivedCount = signal<number>(0);

  statusBadge(s: POStatus): string {
    switch (s) {
      case 'draft':
        return 'badge badge-neutral';
      case 'ordered':
        return 'badge badge-info';
      case 'received':
        return 'badge badge-success';
    }
  }

  lineTotal(line: PurchaseOrderLine): number {
    return line.qty * line.unitCost;
  }

  markOrdered(): void {
    this.orders.update((list) =>
      list.map((o) => (o.id === this.id ? { ...o, status: 'ordered' as POStatus } : o))
    );
  }

  receiveStock(): void {
    this.receivedCount.set(this.order().lines.length);
    this.orders.update((list) =>
      list.map((o) => (o.id === this.id ? { ...o, status: 'received' as POStatus } : o))
    );
    this.received.set(true);
  }
}
